.social-media-buttons {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 16px;
  padding: 0 20px;
}

/* Individual Social Button */
.social-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 48px;
  height: 48px;
  border-radius: 50%;
  transition: all 0.3s ease;
  text-decoration: none;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
}

.social-btn:hover {
  transform: translateY(-4px);
  box-shadow: 0 6px 16px rgba(0, 0, 0, 0.2);
}

.social-btn:active {
  transform: translateY(-2px);
}

/* Social Icon Styling */
.social-icon {
  width: 24px;
  height: 24px;
  flex-shrink: 0;
}

/* Instagram Button - Gradient */
.instagram-btn {
  background: linear-gradient(45deg, #F58529, #DD2A7B, #8134AF, #515BD4);
  color: white;
}

.instagram-btn:hover {
  background: linear-gradient(45deg, #E27522, #C91E6B, #7129A0, #4449C4);
