### CSS Styling - Credentials Section

```css
/* Credentials Section Container */
.credentials-section {
  background: linear-gradient(135deg, #F5F8FF 0%, #FFFFFF 100%);
  padding: 80px 20px;
  position: relative;
  overflow: hidden;
}

.credentials-section::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 4px;
  background: linear-gradient(90deg, #1E4D8B, #0066CC, #20B2AA);
}

.container {
  max-width: 1200px;
  margin: 0 auto;
}

/* Section Header */
.credentials-header {
  text-align: center;
  margin-bottom: 60px;
}

.credentials-title {
  font-family: 'Space Grotesk', sans-serif;
  font-size: 42px;
  font-weight: 700;
  color: #1E4D8B;
  margin: 0 0 12px 0;
  letter-spacing: -0.5px;
}

.credentials-subtitle {
  font-size: 20px;
  color: #666;
  margin: 0;
  font-weight: 400;
}

/* Credentials Grid */
.credentials-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 32px;
  margin-top: 40px;
}

/* Individual Credential Badge */
.credential-badge {
  background: white;
  border-radius: 16px;
  padding: 40px 32px;
  text-align: center;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.08);
  transition: all 0.3s ease;
  border: 2px solid transparent;
  position: relative;
  overflow: hidden;
}

.credential-badge::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 4px;
  background: linear-gradient(90deg, #1E4D8B, #0066CC);
  transform: scaleX(0);
  transition: transform 0.3s ease;
}

.credential-badge:hover {
  transform: translateY(-8px);
  box-shadow: 0 12px 40px rgba(0, 0, 0, 0.15);
  border-color: #1E4D8B;
}

.credential-badge:hover::before {
  transform: scaleX(1);
}

/* Badge Icon */
.badge-icon {
  width: 80px;
  height: 80px;
  margin: 0 auto 24px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(135deg, #F5F8FF 0%, #E8F0FF 100%);
  border-radius: 50%;
  transition: all 0.3s ease;
}

.credential-badge:hover .badge-icon {
  transform: scale(1.1) rotate(5deg);
  background: linear-gradient(135deg, #1E4D8B 0%, #0066CC 100%);
}

.achievement-icon {
  width: 40px;
  height: 40px;
}

.credential-badge:hover .achievement-icon path {
  fill: white;
  stroke: white;
}

/* Badge Text */
.badge-title {
  font-family: 'Space Grotesk', sans-serif;
  font-size: 22px;
  font-weight: 700;
  color: #1E4D8B;
  margin: 0 0 8px 0;
  line-height: 1.3;
}

.badge-subtitle {
  font-size: 16px;
  color: #666;
  margin: 8px 0;
  font-weight: 500;
  line-height: 1.4;
}

.badge-years {
  font-size: 15px;
  color: #FF6B35;
  font-weight: 700;
  margin: 4px 0 12px 0;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.badge-institution {
  font-size: 15px;
  color: #0066CC;
  font-weight: 600;
  margin: 8px 0 12px 0;
  line-height: 1.4;
}

.badge-description {
  font-size: 14px;
  color: #666;
  line-height: 1.6;
  margin: 12px 0 0 0;
}

/* Castle Connolly Badge Link */
.badge-link {
  display: inline-block;
  margin-top: 16px;
  padding: 10px 20px;
  background: linear-gradient(135deg, #C9A961 0%, #DAA520 100%);
  color: white;
  text-decoration: none;
  border-radius: 8px;
  font-size: 14px;
  font-weight: 600;
  transition: all 0.3s ease;
  box-shadow: 0 2px 8px rgba(201, 169, 97, 0.3);
}

.badge-link:hover {
  background: linear-gradient(135deg, #B89750 0%, #C9A961 100%);
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(201, 169, 97, 0.4);
}

/* Specific Badge Styling */

/* Castle Connolly - Gold Theme */
.castle-connolly-badge {
  border-top: 4px solid #C9A961;
}

.castle-connolly-badge .badge-icon {
  background: linear-gradient(135deg, #FFF8E7 0%, #FFEFD5 100%);
}

/* Fellowship - Blue Theme */
.fellowship-badge {
  border-top: 4px solid #1E4D8B;
}

/* Board Certified - Green Theme */
.board-badge {
  border-top: 4px solid #28A745;
}

.board-badge .badge-icon {
  background: linear-gradient(135deg, #E8F5E9 0%, #C8E6C9 100%);
}

/* Alpha Omega Alpha - Gold Theme */
.aoa-badge {
  border-top: 4px solid #DAA520;
}

.aoa-badge .badge-icon {
  background: linear-gradient(135deg, #FFF8DC 0%, #FFE4B5 100%);
}

/* Faculty - Blue Theme */
.faculty-badge {
  border-top: 4px solid #0066CC;
}

/* Research - Orange Theme */
.research-badge {
  border-top: 4px solid #FF6B35;
}

.research-badge .badge-icon {
  background: linear-gradient(135deg, #FFF0E6 0%, #FFE4D1 100%);
}

/* Mobile Responsive */
@media (max-width: 768px) {
  .credentials-section {
    padding: 60px 15px;
  }

  .credentials-title {
    font-size: 32px;
  }

  .credentials-subtitle {
    font-size: 18px;
  }

