      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16">
        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
          {BLOG_POSTS.map((post) => (
            <Link 
              key={post.slug} 
              to={`/blog/${post.slug}`} 
              className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden hover:shadow-lg transition-all hover:-translate-y-1 group flex flex-col"
            >
              <div className="h-48 overflow-hidden relative">
                 <div className="absolute top-4 left-4 bg-white/90 backdrop-blur px-3 py-1 rounded-full text-xs font-bold text-primary flex items-center gap-1 z-10">
                   <Tag size={12} /> {post.category}
                 </div>
                 <img 
                   src={post.image} 
                   alt={post.title} 
                   className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105" 
                 />
              </div>
              <div className="p-6 flex flex-col flex-grow">
                 <div className="flex items-center gap-4 text-xs text-gray-500 mb-3">
                   <span className="flex items-center gap-1"><Calendar size={12} /> {post.date}</span>
                   <span className="flex items-center gap-1"><Clock size={12} /> {post.readTime}</span>
                 </div>
                 <h2 className="text-xl font-bold text-gray-900 mb-3 group-hover:text-primary transition-colors line-clamp-2">
                   {post.title}
                 </h2>
                 <p className="text-gray-600 text-sm leading-relaxed mb-4 line-clamp-3 flex-grow">
                   {post.excerpt}
                 </p>
                 <span className="text-primary font-semibold text-sm flex items-center gap-1 mt-auto">
                   Read Article <ChevronRight size={16} className="group-hover:translate-x-1 transition-transform" />
                 </span>
              </div>
            </Link>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Blog;

